    for num in nums:
        depth, pos, val = num // 100, num % 100 // 10, num % 10
        cur = root
        for d in reversed(range(depth - 1)):
            if (pos >> d) & 1:
                if not cur.right: cur.right = TreeNode(val)
                cur = cur.right
            else:
                if not cur.left: cur.left = TreeNode(val)
                cur = cur.left
    return sumPaths(root, 0)
